import { a11y, page, render, renderHook } from "#test/browser"
import { Highlight, useHighlight } from "."

describe("<Highlight />", () => {
  test("renders component correctly", async () => {
    await a11y(<Highlight query="highlight">Highlight</Highlight>)
  })

  test("sets `displayName` correctly", () => {
    expect(Highlight.name).toBe("Highlight")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Highlight data-testid="highlight" query="highlight">
        Highlight
      </Highlight>,
    )
    expect(page.getByTestId("highlight").element().tagName).toBe("P")
  })

  test.each([[], ""])(
    "useHighlight returns no matches if queries is empty but returns original value",
    async (query) => {
      const text = "this is an ordinary text which should not have any matches"

      const { result } = await renderHook(() =>
        useHighlight({
          query,
          text,
        }),
      )

      expect(result.current).toHaveLength(1)
      expect(result.current[0]?.match).toBeFalsy()
      expect(result.current[0]?.text).toBe(text)
    },
  )

  test("fragment prop works correctly", async () => {
    const { container } = await render(
      <Highlight fragment query="">
        Highlight
      </Highlight>,
    )
    expect(container.firstChild?.nodeName).toBe("#text")
  })

  test("fragment prop renders Mark for matched text", async () => {
    const { container } = await render(
      <Highlight fragment query="High">
        Highlight
      </Highlight>,
    )

    const mark = page.getByText("High")
    expect(mark.element().tagName).toBe("MARK")
    expect(container.querySelector("p")).toBeNull()
  })

  test("renders non-matching chunks as plain text alongside matches", async () => {
    await render(
      <Highlight data-testid="highlight" query="world">
        Hello world
      </Highlight>,
    )

    const container = page.getByTestId("highlight")
    const mark = page.getByText("world")
    expect(mark.element().tagName).toBe("MARK")
    expect(container.element().tagName).toBe("P")
    await expect.element(container).toHaveTextContent("Hello world")
  })

  test("markProps prop works correctly", async () => {
    await render(
      <Highlight query="Highlight" markProps={{ borderRadius: "12px" }}>
        Highlight
      </Highlight>,
    )
    await expect.element(page.getByText("Highlight")).toHaveStyle({
      borderRadius: "12px",
    })
  })

  test("useHighlight matches correctly", async () => {
    const query = ["", "text"]

    const { result } = await renderHook(() =>
      useHighlight({
        query: query,
        text: "this is an ordinary text which should have one match ",
      }),
    )

    expect(result.current).toStrictEqual([
      { match: false, text: "this is an ordinary " },
      { match: true, text: "text" },
      { match: false, text: " which should have one match " },
    ])
  })
})

import type { FC } from "react"
import type { MarkProps } from "../mark"
import type { TextProps } from "../text"
import { Fragment } from "react"
import { Mark } from "../mark"
import { Text } from "../text"
import { useHighlight } from "./use-highlight"

export interface HighlightProps extends Omit<TextProps, "children"> {
  /**
   * The text used for searching.
   */
  children: string
  /**
   * Can be a single string or an array of strings. These are the terms that are highlighted in the text.
   */
  query: string | string[]
  /**
   * If `true`, `Fragment` is used for rendering.
   *
   * @default false
   */
  fragment?: boolean
  /**
   * Properties passed to the Mark component which is used to highlight the matched terms.
   */
  markProps?: MarkProps
}

/**
 * `Highlight` is a component that highlights specified strings within text. By default, it renders a `p` element.
 *
 * @see https://yamada-ui.com/docs/components/highlight
 */
export const Highlight: FC<HighlightProps> = ({
  children: text,
  fragment = false,
  query,
  markProps,
  ...rest
}) => {
  const chunks = useHighlight({ query, text })
  const { colorScheme } = rest

  if (fragment) {
    return (
      <>
        {chunks.map(({ match, text }, index) =>
          match ? (
            <Mark key={index} colorScheme={colorScheme} {...markProps}>
              {text}
            </Mark>
          ) : (
            <Fragment key={index}>{text}</Fragment>
          ),
        )}
      </>
    )
  } else {
    return (
      <Text {...rest}>
        {chunks.map(({ match, text }, index) =>
          match ? (
            <Mark key={index} colorScheme={colorScheme} {...markProps}>
              {text}
            </Mark>
          ) : (
            <Fragment key={index}>{text}</Fragment>
          ),
        )}
      </Text>
    )
  }
}

import { useMemo } from "react"
import { toArray } from "@yamada-ui/react"

export interface Chunk {
  match: boolean
  text: string
}

const escapeRegexp = (term: string): string =>
  term.replace(/[|\\{}()[\]^$+*?.-]/g, (char: string) => `\\${char}`)

const createRegexp = (query: string[]): RegExp | undefined => {
  query = query.filter(Boolean).map((text) => escapeRegexp(text.trim()))

  if (query.length) return new RegExp(`(${query.join("|")})`, "ig")
}

export interface UseHighlightProps {
  query: string | string[]
  text: string
}

export const useHighlight = ({ query, text }: UseHighlightProps) => {
  const chunks = useMemo(() => {
    const regexp = createRegexp(toArray(query))

    if (!regexp) return [{ match: false, text }]

    return text
      .split(regexp)
      .filter(Boolean)
      .map((text) => ({ match: regexp.test(text), text }))
  }, [text, query])

  return chunks
}

export type UseHighlightReturn = ReturnType<typeof useHighlight>
